import{_ as o}from"./chunks/export.CcCpNx0w.js";import{_ as t,o as a,c as r,ae as i}from"./chunks/framework.C00B0EYs.js";const m=JSON.parse('{"title":"Export Workflow","description":"Prepare and export a project package from Motor Sound Editor.","frontmatter":{"title":"Export Workflow","description":"Prepare and export a project package from Motor Sound Editor."},"headers":[],"relativePath":"docs/guide/export.md","filePath":"docs/guide/export.md"}'),n={name:"docs/guide/export.md"};function s(l,e,d,p,c,u){return a(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="export-workflow" tabindex="-1">Export Workflow <a class="header-anchor" href="#export-workflow" aria-label="Permalink to &quot;Export Workflow&quot;">​</a></h1><p>After you finish editing tracks and adjusting curves, you can export the current project as a packaged output for the target simulator workflow.</p><h2 id="_1-checks-before-export" tabindex="-1">1. Checks before export <a class="header-anchor" href="#_1-checks-before-export" aria-label="Permalink to &quot;1. Checks before export&quot;">​</a></h2><p>Before exporting, make sure that:</p><ul><li><strong>Eligible tracks exist</strong>: the export engine only processes tracks that are <strong>enabled</strong>, <strong>unmuted</strong>, and <strong>assigned an audio asset</strong>.</li><li><strong>At least one exportable track is valid</strong>: if every exportable track is missing audio, the export step fails immediately.</li></ul><h2 id="_2-export-dialog" tabindex="-1">2. Export dialog <a class="header-anchor" href="#_2-export-dialog" aria-label="Permalink to &quot;2. Export dialog&quot;">​</a></h2><p><img src="'+o+'" alt="Project export"></p><p>When you click the export button, the app opens the <strong>Export File</strong> dialog. This is where you choose the output format and audio options.</p><h2 id="_3-export-format" tabindex="-1">3. Export format <a class="header-anchor" href="#_3-export-format" aria-label="Permalink to &quot;3. Export format&quot;">​</a></h2><ul><li><strong>BVE</strong> is the only active export target today. The app packages the result as a standard <strong>ZIP archive</strong>, for example <code>[ProjectName]-BVE.zip</code>.</li><li><strong>OpenBVE / MTR</strong> still appear in the menu as disabled placeholders for future expansion.</li></ul><h2 id="_4-sample-rate" tabindex="-1">4. Sample rate <a class="header-anchor" href="#_4-sample-rate" aria-label="Permalink to &quot;4. Sample rate&quot;">​</a></h2><p>You can choose a global sample rate for exported audio.</p><ul><li>Available values are <code>22050 Hz</code>, <code>32000 Hz</code>, <code>44100 Hz</code>, <code>48000 Hz</code>, and <code>96000 Hz</code>.</li><li><code>44100 Hz</code> is usually the practical default because it balances audio quality and file size well.</li></ul><h2 id="_5-format-conversion-and-automatic-adaptation" tabindex="-1">5. Format conversion and automatic adaptation <a class="header-anchor" href="#_5-format-conversion-and-automatic-adaptation" aria-label="Permalink to &quot;5. Format conversion and automatic adaptation&quot;">​</a></h2><p>Motor Sound Editor can import both <code>.ogg</code> and <code>.wav</code> audio. During export, the app performs any required conversion automatically so the output matches the target format.</p><p>For example, if the project contains <code>.ogg</code> audio and the export target requires WAV, the dialog shows a warning message explaining that OGG files will be converted to WAV during export.</p><p>You do not need to transcode files manually. Once the settings look correct, click <strong>Export</strong> to finish the package.</p>',17)])])}const f=t(n,[["render",s]]);export{m as __pageData,f as default};
